def kosaraju(graph):
    """
    Kosaraju algoritması ile güçlü bağlantılı bileşenleri bulur.

    Args:
        graph: Sözlük kullanarak temsil edilen bir grafik. Anahtarlar düğümlerdir ve değerler bitişik düğümlerin bir listesidir.

    Returns:
        Güçlü bağlantılı bileşenlerin bir listesi. Her bileşen, düğümlerin bir listesidir.
    """

    def dfs1(node, visited, stack):
        visited[node] = True
        for neighbor in graph.get(node, []):
            if not visited[neighbor]:
                dfs1(neighbor, visited, stack)
        stack.append(node)

    def dfs2(node, visited, component, reversed_graph):
        visited[node] = True
        component.append(node)
        for neighbor in reversed_graph.get(node, []):
            if not visited[neighbor]:
                dfs2(neighbor, visited, component, reversed_graph)

    # Adım 1: Grafiğin düğümlerini bitirme zamanlarına göre sıralamak için DFS'yi kullanın.
    visited = {node: False for node in graph}
    stack = []
    for node in graph:
        if not visited[node]:
            dfs1(node, visited, stack)

    # Adım 2: Grafiği transpoze edin.
    reversed_graph = {}
    for node in graph:
        for neighbor in graph.get(node, []):
            reversed_graph.setdefault(neighbor, []).append(node)

    # Adım 3: Bitirme zamanlarına göre düğümler üzerinde DFS'yi ters grafikte gerçekleştirin.
    visited = {node: False for node in graph}
    scc = []
    while stack:
        node = stack.pop()
        if not visited[node]:
            component = []
            dfs2(node, visited, component, reversed_graph)
            scc.append(component)

    return scc


if __name__ == '__main__':
    # Örnek grafik
    graph = {
        0: [1, 2],
        1: [2, 3],
        2: [0, 3],
        3: [4],
        4: [5],
        5: [6],
        6: [4, 7],
        7: [7]
    }

    # Güçlü bağlantılı bileşenleri bulun
    scc = kosaraju(graph)

    # Sonuçları yazdır
    print("Güçlü Bağlantılı Bileşenler:")
    for component in scc:
        print(component)
